create extension if not exists pgcrypto;
create table public.admin_users (user_id uuid primary key references auth.users(id) on delete cascade, created_at timestamptz not null default now());
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from public.admin_users where user_id=auth.uid())$$;
create table public.profiles (id uuid primary key default gen_random_uuid(), user_id uuid unique references auth.users(id) on delete set null, full_name text not null default '', professional_title text not null default '', profile_image_url text, biography text not null default '', email text not null default '', phone text, location text, github_url text, linkedin_url text, facebook_url text, resume_url text, availability_status text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.categories (id uuid primary key default gen_random_uuid(), name text not null unique, slug text not null unique, icon text, sort_order int not null default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.technologies (id uuid primary key default gen_random_uuid(), name text not null unique, slug text not null unique, icon text, category text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.projects (id uuid primary key default gen_random_uuid(), title text not null, slug text not null unique, short_description text not null, full_description text, problem_statement text, solution text, role text, client_name text, cover_image_url text, live_url text, github_url text, start_date date, completion_date date, project_status text not null default 'Completed', is_featured boolean not null default false, is_published boolean not null default false, is_archived boolean not null default false, sort_order int not null default 0, seo_title text, seo_description text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.project_images (id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id) on delete cascade, image_url text not null, image_caption text, sort_order int not null default 0, created_at timestamptz not null default now());
create table public.project_categories (project_id uuid references public.projects(id) on delete cascade, category_id uuid references public.categories(id) on delete restrict, primary key(project_id,category_id));
create table public.project_technologies (project_id uuid references public.projects(id) on delete cascade, technology_id uuid references public.technologies(id) on delete restrict, primary key(project_id,technology_id));
create table public.project_features (id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id) on delete cascade, feature text not null, sort_order int not null default 0);
create table public.skills (id uuid primary key default gen_random_uuid(), name text not null, category text not null, icon text, proficiency_level int not null default 3 check(proficiency_level between 1 and 5), sort_order int not null default 0, is_published boolean not null default true, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.experiences (id uuid primary key default gen_random_uuid(), job_title text not null, organization text not null, location text, start_date date not null, end_date date, is_current boolean not null default false, description text, responsibilities jsonb not null default '[]', technologies text[] not null default '{}', sort_order int not null default 0, is_published boolean not null default true, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.services (id uuid primary key default gen_random_uuid(), title text not null, description text not null, icon text, pricing_text text, sort_order int not null default 0, is_published boolean not null default true, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.contact_inquiries (id uuid primary key default gen_random_uuid(), full_name text not null, email text not null, company text, phone text, subject text not null, project_type text, estimated_budget text, message text not null, status text not null default 'New' check(status in ('New','Read','Replied','Archived')), internal_notes text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.public_settings (setting_key text primary key, setting_value text not null, updated_at timestamptz not null default now()); create table public.website_settings (setting_key text primary key, setting_value text not null, updated_at timestamptz not null default now());
create index projects_public_idx on public.projects(is_published,is_archived,sort_order); create index inquiries_status_idx on public.contact_inquiries(status,created_at desc);
alter table public.admin_users enable row level security; alter table public.profiles enable row level security; alter table public.projects enable row level security; alter table public.categories enable row level security; alter table public.technologies enable row level security; alter table public.project_images enable row level security; alter table public.project_categories enable row level security; alter table public.project_technologies enable row level security; alter table public.project_features enable row level security; alter table public.skills enable row level security; alter table public.experiences enable row level security; alter table public.services enable row level security; alter table public.contact_inquiries enable row level security; alter table public.public_settings enable row level security; alter table public.website_settings enable row level security;
create policy "public profile" on public.profiles for select using(true); create policy "public published projects" on public.projects for select using(is_published and not is_archived); create policy "public categories" on public.categories for select using(true); create policy "public technologies" on public.technologies for select using(true); create policy "public project relations" on public.project_categories for select using(exists(select 1 from public.projects p where p.id=project_id and p.is_published and not p.is_archived)); create policy "public project technology relations" on public.project_technologies for select using(exists(select 1 from public.projects p where p.id=project_id and p.is_published and not p.is_archived)); create policy "public features" on public.project_features for select using(exists(select 1 from public.projects p where p.id=project_id and p.is_published and not p.is_archived)); create policy "public images" on public.project_images for select using(exists(select 1 from public.projects p where p.id=project_id and p.is_published and not p.is_archived)); create policy "public skills" on public.skills for select using(is_published); create policy "public experience" on public.experiences for select using(is_published); create policy "public services" on public.services for select using(is_published); create policy "public settings" on public.public_settings for select using(true); create policy "public submit inquiry" on public.contact_inquiries for insert with check(char_length(message)>=20);
do $$ declare t text; begin foreach t in array array['profiles','projects','categories','technologies','project_images','project_categories','project_technologies','project_features','skills','experiences','services','contact_inquiries','public_settings','website_settings'] loop execute format('create policy "admin manage %s" on public.%I for all using (public.is_admin()) with check (public.is_admin())',t,t); end loop; end $$;
insert into storage.buckets(id,name,public) values ('project-images','project-images',true),('profile-assets','profile-assets',true),('resume-files','resume-files',true),('website-assets','website-assets',true) on conflict do nothing;
create policy "public storage read" on storage.objects for select using(bucket_id in ('project-images','profile-assets','resume-files','website-assets')); create policy "admin storage manage" on storage.objects for all using(public.is_admin()) with check(public.is_admin());
